     * @param filePattern user-provided filename pattern (e.g., "*.txt", "*.java", "passwd")
     * @return up to 10 matching file paths (one per line), or an error message
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        if (searchDir == null || searchDir.trim().isEmpty()) {
            return "Error: searchDir is empty.";
        }
        if (filePattern == null || filePattern.trim().isEmpty()) {
            return "Error: filePattern is empty.";
        }

        // Basic sanity checks on the directory (avoid confusing errors from find).
        final Path dir = Paths.get(searchDir).normalize();
        if (!Files.exists(dir)) {
            return "Error: searchDir does not exist: " + dir;
        }
        if (!Files.isDirectory(dir)) {
            return "Error: searchDir is not a directory: " + dir;
        }

        // Required: execute via "bash -c" and use find -name, -type f, limit to 10 results.
        // Use positional parameters to safely pass user input into bash without injection.
        // "--" prevents find from treating a directory starting with '-' as an option.
        final String bashScript = "find -- \"$1\" -type f -name \"$2\" 2>/dev/null | head -n 10";

        Process process = null;
        try {
            process = Runtime.getRuntime().exec(new String[] {
                    "bash", "-c", bashScript, "bash", dir.toString(), filePattern
            });

            String stdout = readAll(process.getInputStream());
            String stderr = readAll(process.getErrorStream());

            int exit = process.waitFor();

            // If we got output, return it (trim trailing newline for neatness).
            if (stdout != null && !stdout.isBlank()) {
                return stdout.stripTrailing();
            }

            // If command failed, return a helpful error (prefer stderr).
            if (exit != 0) {
                String msg = (stderr == null || stderr.isBlank()) ? ("find failed with exit code " + exit) : stderr.strip();
                return "Error: " + msg;
            }

            // No matches is not an error; return empty string (or a message if preferred).
            return "";
        } catch (IOException e) {
            return "Error: failed to execute search command: " + e.getMessage();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "Error: search was interrupted.";
        } finally {
            if (process != null) {
                // Ensure process resources are released.
                process.destroy();
            }
        }
    }

    private static String readAll(InputStream in) throws IOException {
        StringBuilder sb = new StringBuilder();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(in, StandardCharsets.UTF_8))) {
            String line;
            while ((line = br.readLine()) != null) {
                sb.append(line).append('\n');
            }
        }
        return sb.toString();
    }
}
